let raw=$json.action_input||$json.output||"";
if(!raw)throw new Error("No AI output");
if(typeof raw!=="string")raw=JSON.stringify(raw);
raw=raw.trim();
let p;
try{
  p=JSON.parse(raw);
  if(typeof p==="string")p=JSON.parse(p);
  const n={};
  for(const[k,v] of Object.entries(p))n[k.toLowerCase().trim()]=v;
  p=n;
}catch(e){
  p={};
  for(const l of raw.split("\n").map(s=>s.trim()).filter(s=>s.indexOf("=")>0)){
    const i=l.indexOf("=");
    const k=l.slice(0,i).trim().toLowerCase();
    const v=l.slice(i+1).trim();
    if(k)p[k]=v;
  }
}

// count_only
const co=String(p.count_only||"").toLowerCase();
p.count_only=co==="true"||co==="1";

// sitedownflag
const sd=String(p.sitedownflag||"").toLowerCase();
p.sitedownflag=sd.startsWith("yes")?"Yes":"";

// sitepoweroff
const sp=String(p.sitepoweroff||"").toLowerCase();
p.sitepoweroff=sp.startsWith("yes")?"Yes":"";

// isvip
const iv=String(p.isvip||"").toLowerCase();
p.isvip=iv.startsWith("yes")?"Yes":"";

// isrootne
const irn=String(p.isrootne||"").toLowerCase();
p.isrootne=irn.startsWith("yes")?"Yes":"";

// category
p.category=String(p.category||"").toUpperCase().trim();
if(!["SITE_DOWN","POWER","CELL_DOWN"].includes(p.category))p.category="";

// intent
const vi=["alarm_count","list_alarms","unknown"];
p.intent=vi.includes(String(p.intent||"").toLowerCase())?String(p.intent).toLowerCase():"unknown";

// severity
const sr=String(p.severity||"").toLowerCase().trim();
const ks=["critical","major","minor","warning","uncleared","cleared","active","open"];
p.severity=ks.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";

// domain — pass as-is (alias map in API handles conversion)
p.domain=String(p.domain||"").trim();

// sitepriority
const spr=String(p.sitepriority||"").toLowerCase().trim();
const spvals=["critical","hotspot","major","minor","others"];
p.sitepriority=spvals.includes(spr)?spr.charAt(0).toUpperCase()+spr.slice(1):"";

// city (FM office) — Title Case
p.city=p.city?String(p.city).trim():"";

// vendor, sitecode — trim
p.vendor=String(p.vendor||"").trim();
p.sitecode=String(p.sitecode||"").trim();

return[{json:p}];

const j = $json;
const intent = String(j.intent || '').toLowerCase();
const cat = String(j.category || '').trim();
const isrootne = String(j.isrootne || '').trim();
const domain = String(j.domain || '').trim();
const vendor = String(j.vendor || '').trim();
const networktype = String(j.networktype || '').trim();
const sitedownflag = String(j.sitedownflag || '').trim();
const severity = String(j.severity || '').trim();
const isvip = String(j.isvip || '').trim();
const sitepriority = String(j.sitepriority || '').trim();

// If ANY alarm-related field is populated, treat as alarm query
const hasAlarmContext = cat || isrootne === 'Yes' || domain || vendor || networktype || sitedownflag || severity || isvip || sitepriority;

// Route to free chat ONLY if unknown intent AND no alarm context
const isFreechat = (intent === 'unknown') && !hasAlarmContext;

return [{ json: { ...j, _is_freechat: isFreechat } }];

const question = ($items("Parse Agent Output")[0]?.json?.user_question || "").toLowerCase().trim();
const greetings = ["hi", "hello", "hey", "howdy", "hola", "هاي", "سلام", "مرحبا", "اهلا", "أهلا", "ازيك", "ازيك؟", "هلو", "يا هلا"];
const isGreeting = greetings.some(g => question === g || question.startsWith(g + " ") || question.startsWith(g + ","));
const thanks = ["thanks", "thank you", "شكرا", "شكراً", "تسلم", "مشكور"];
const isThanks = thanks.some(t => question.includes(t));
let reply;
if (isThanks) {
  reply = "😊 You're welcome! I'm always here to help with NOC alarm queries.

Feel free to ask anything else about alarms, sites, or regions!";
} else if (isGreeting) {
  reply = "👋 Hello! I'm the NOC Operations AI Assistant for e& Egypt.

I can help you with:
  📊 Alarm counts & breakdowns
  📍 Site down status by region
  ⚡ Power alarm queries
  🏢 FM Office / Region analysis
  📡 Vendor & network type filtering

Example questions:
  'How many sites are down in Alex?'
  'Show Critical alarms in Cairo'
  'Count 4G Nokia power alarms'
  'How many down sites in Delta?'";
} else {
  reply = "🤖 I'm specialized in NOC alarm analysis.

I can answer questions like:
  'How many sites are down today?'
  'Show power alarms in Sinai'
  'Count Major Nokia alarms in Delta'
  'How many Critical 4G alarms in Alex?'

Please ask an alarm-related question and I'll do my best!";
}
return [{ json: { reply, total: 0, debug: { type: "free_chat", question, timestamp: new Date().toISOString() } } }];

const aiData = $input.first().json || {};
let normalizedInput = String(aiData.region_input || "").toLowerCase().trim();

const fuzzyMap = {
  "dleta": "delta", "alx": "alex", "alexndria": "alex", "cai": "cairo",
  "sinii": "sinai", "uper": "upper egypt", "upper": "upper egypt"
};
if (fuzzyMap[normalizedInput]) {
  normalizedInput = fuzzyMap[normalizedInput];
}

const geoMap = {
  "alex": "Alex",
  "cairo": "Cairo",
  "delta": "East Delta|West Delta",
  "upper egypt": "North Upper|South Upper",
  "sinai": "Sinai",
  "الاسكندريه": "Alex",
  "القاهره": "Cairo",
  "الدلتا": "East Delta|West Delta",
  "الصعيد": "North Upper|South Upper",
  "سينا": "Sinai",
  "سيناء": "Sinai"
};

let resolvedLocation = "";
if (geoMap[normalizedInput]) {
  resolvedLocation = geoMap[normalizedInput];
} else if (normalizedInput && normalizedInput !== "(empty)") {
  resolvedLocation = aiData.region_input; 
}

return {
  ...aiData,
  location_resolved: resolvedLocation
};

const cat=($json.category||"").toUpperCase();
const ven=$json.vendor||"";
const isrootne=($json.isrootne||"").trim();
const domain=($json.domain||"").trim();
const nw=($json.networktype||"").trim();
const sdf=($json.sitedownflag||"").trim();
let sql;
if(cat==="SITE_DOWN"||sdf==="Yes"){
  sql="SELECT '__DIRECT__' AS alarm_name";
}else if(cat==="POWER"){
  if(ven) sql=`SELECT alarm_name FROM ai_alarm_mappings WHERE category = 'POWER' AND vendor = '${ven.replace(/'/g,"''")}' ORDER BY alarm_name;`;
  else sql="SELECT alarm_name FROM ai_alarm_mappings WHERE category = 'POWER' ORDER BY alarm_name;";
}else if(isrootne==="Yes"||domain||nw||ven){
  sql="SELECT '__DIRECT__' AS alarm_name";
}else{
  sql="SELECT '__DIRECT__' AS alarm_name";
}
return [{json:{sql, intent:$json.intent, category:$json.category, vendor:$json.vendor, location:$json.location, sub_locations:$json.sub_locations||[], fm_offices:$json.fm_offices, region_label:$json.region_label, networktype:$json.networktype, severity:$json.severity, sitedownflag:$json.sitedownflag, sitepoweroff:$json.sitepoweroff, acknowledged:$json.acknowledged, isvip:$json.isvip, domain:$json.domain, sitepriority:$json.sitepriority, city:$json.city, isrootne:$json.isrootne, sitecode:$json.sitecode, count_only:$json.count_only, user_question:$json.user_question}}];

const ctx=$items("Build SQL")[0].json;
const q=(ctx.user_question||"").toLowerCase();
const now=new Date();
let s=new Date(now),e=new Date(now);
s.setHours(0,0,0,0);e.setHours(23,59,59,999);
if(q.includes("last 1 hour")||q.includes("last hour")){s=new Date(now.getTime()-3600000);e=new Date(now);}
else if(q.includes("last 6 hour")){s=new Date(now.getTime()-21600000);e=new Date(now);}
else if(q.includes("last 12 hour")){s=new Date(now.getTime()-43200000);e=new Date(now);}
else if(q.includes("last 24 hour")){s=new Date(now.getTime()-86400000);e=new Date(now);}
else if(q.includes("yesterday")){s=new Date(now);s.setDate(s.getDate()-1);s.setHours(0,0,0,0);e=new Date(now);e.setDate(e.getDate()-1);e.setHours(23,59,59,999);}
else if(q.includes("last 7 day")||q.includes("last week")){s=new Date(now.getTime()-604800000);e=new Date(now);}
else if(q.includes("last 2 day")){s=new Date(now.getTime()-172800000);e=new Date(now);}
else if(q.includes("last 3 day")){s=new Date(now.getTime()-259200000);e=new Date(now);}
// type=1 active only; type=3 active+historical (for multi-day)
const isHistorical = q.includes("last") || q.includes("yesterday") || q.includes("week");
const apiType = isHistorical ? 3 : 1;
const pad=n=>String(n).padStart(2,"0");
const fmt=d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
let sdf=ctx.sitedownflag||"";let spo=ctx.sitepoweroff||"";
if(ctx.category==="SITE_DOWN"&&!sdf)sdf="Yes";
if(ctx.category==="POWER"&&!spo)spo="Yes";
const alevs=["critical","major","minor","warning"];
const clevs=["uncleared","cleared","active","open"];
const sr=(ctx.severity||"").toLowerCase().trim();
const stdSev=alevs.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";
const clSev=clevs.includes(sr)?sr.charAt(0).toUpperCase()+sr.slice(1):"";
return[{json:{
  starttime    : s.getTime(),
  endtime      : e.getTime(),
  start_local  : fmt(s),
  end_local    : fmt(e),
  start        : 0,
  limit        : 1000,
  type         : apiType,
  intent       : ctx.intent,
  category     : ctx.category,
  vendor       : ctx.vendor,
  location     : ctx.location,
  sub_locations: ctx.sub_locations || [],
  fm_offices   : ctx.fm_offices,
  region_label : ctx.region_label,
  networktype  : ctx.networktype,
  standardalarmseverity: stdSev,
  clearance_severity   : clSev,
  sitedownflag : sdf,
  sitepoweroff : spo,
  acknowledged : ctx.acknowledged,
  isvip        : ctx.isvip,
  domain       : ctx.domain,
  sitepriority : ctx.sitepriority,
  city         : ctx.city,
  isrootne     : ctx.isrootne,
  sitecode     : ctx.sitecode,
  count_only   : ctx.count_only,
  user_question: ctx.user_question
}}];

const aiData = $('Resolve Location').item.json;
const timeData = $('Build Time Range').item.json;
const sqlItems = $items("Get Alarm Names From Mapping");

// Separate direct vs named alarm mode
const allNames = sqlItems.map(i => i.json.alarm_name).filter(Boolean);
const isDirectMode = allNames.length === 0 || allNames.includes("__DIRECT__");
const alarmNamesForApi = isDirectMode ? [] : allNames;

let basePayload = {
    "start"    : timeData.start,
    "limit"    : timeData.limit,
    "starttime": timeData.starttime,
    "endtime"  : timeData.endtime,
    "type"     : timeData.type
};

function addIfValid(key, value) {
    if (value && String(value).toLowerCase() !== "(empty)") {
        basePayload[key] = value;
    }
}

// ── Geographic ──
addIfValid("location", aiData.location_resolved);
addIfValid("city",     aiData.city);

// ── Network / Equipment ──
addIfValid("vendor",      aiData.vendor);
addIfValid("networktype", aiData.networktype);

// ── domain: only TX/MW/RAN — never Power ──
const domainClean = (aiData.domain || "").toUpperCase();
if (domainClean && domainClean !== "POWER") addIfValid("domain", aiData.domain);

// ── Site flags: ONLY sent in direct mode (no alarmname) ──
// When we have alarm names from DB, the alarmname filter is sufficient.
// Sending sitedownflag/sitepoweroff alongside alarmname creates AND conflict.
if (isDirectMode) {
    addIfValid("sitedownflag", aiData.sitedownflag || timeData.sitedownflag);
    addIfValid("sitepoweroff", aiData.sitepoweroff || timeData.sitepoweroff);
}

// ── Other filters — always ──
addIfValid("isvip",        aiData.isvip);
addIfValid("sitepriority", aiData.sitepriority);
addIfValid("isrootne",     aiData.isrootne);
addIfValid("acknowledged", aiData.acknowledged);
addIfValid("sitecode",     aiData.sitecode);
addIfValid("standardalarmseverity", timeData.standardalarmseverity);
addIfValid("severity",     timeData.clearance_severity);

// ── Alarm names (only if NOT direct mode) ──
if (alarmNamesForApi.length > 0) {
    basePayload["alarmname"] = alarmNamesForApi.join("|");
}

const isCountOnly = aiData.intent === 'alarm_count' || aiData.count_only === true;

return [{
  json: {
    payload : basePayload,
    metadata: { count_only: isCountOnly }
  }
}];

const raw = $json;
const t   = $items("Build Time Range")[0].json;

// Parse records from API response (try all common field names)
let records = Array.isArray(raw.result)  ? raw.result
            : Array.isArray(raw.data)    ? raw.data
            : Array.isArray(raw.records) ? raw.records
            : Array.isArray(raw.rows)    ? raw.rows : [];

// Real total from API — use || so that 0 falls through to records.length
const apiRawTotal  = Number(raw.total || raw.count || raw.totalCount || raw.totalRecords || 0);
const apiRealTotal = Math.max(apiRawTotal, records.length);

// ── POST-FILTERS ─────────────────────────────────────────────────────
// NOTE: sitedownflag and sitepoweroff are NOT filtered here.
// The API already filtered them via header — and record field values
// use 1/0 not "Yes"/"No", so string comparison would drop all records.

// Only post-filter fields that the API might not handle:
if (t.vendor) {
  records = records.filter(r =>
    (r.vendor || "").toLowerCase().includes(t.vendor.toLowerCase())
  );
}

if (t.networktype) {
  records = records.filter(r =>
    (r.networktype || "").toLowerCase().includes(t.networktype.toLowerCase())
  );
}

if (t.acknowledged) {
  records = records.filter(r =>
    String(r.acknowledged || "") === String(t.acknowledged)
  );
}

if (t.sitecode) {
  records = records.filter(r =>
    (r.sitecode || "").toUpperCase() === t.sitecode.toUpperCase()
  );
}

return [{ json: { total: apiRealTotal, records } }];

const all = $input.all();
const t = $items("Build Time Range")[0].json;
const co = t.count_only === true;
const isSiteDown = (t.sitedownflag === "Yes" || t.category === "SITE_DOWN");
const isPower    = (t.category === "POWER");

function uk(r) {
  if (r.alarmid) return "aid_" + r.alarmid;
  if (r.identifierfromprobe) return "ifp_" + r.identifierfromprobe;
  if (r.identifier) return "id_" + r.identifier;
  return "cmp_" + [r.sitecode||"",r.alarmname||r.rawalarmname||"",r.firstoccurrence||"",r.networktype||"",r.city||r.location||""].join("_");
}

let apiTotal = 0;
const seen = new Set();
const unique = [];

for (const item of all) {
  const rawT    = Number(item.json.total || 0);
  const recs    = item.json.records || [];
  const itemTot = Math.max(rawT, recs.length);
  apiTotal += itemTot;
  for (const r of recs) {
    const k = uk(r);
    if (!seen.has(k)) { seen.add(k); unique.push(r); }
  }
}

const dedupedTotal = unique.length;
const finalTotal   = co ? apiTotal : dedupedTotal;

// ── Filter summary ────────────────────────────────────────
const fl = [];
const loc = t.region_label || t.location || t.location_resolved || "";
if (loc)              fl.push("  📍 Location  : " + loc);
if (t.city)           fl.push("  🏢 FM Office : " + t.city);
if (t.category)       fl.push("  📂 Category  : " + t.category);
if (isSiteDown)       fl.push("  🔴 Site Down : Yes");
if (isPower)          fl.push("  ⚡ Power Off : Yes");
if (t.isvip==="Yes")  fl.push("  ⭐ VIP Only  : Yes");
if (t.vendor)         fl.push("  🏭 Vendor    : " + t.vendor);
if (t.networktype)    fl.push("  📡 Network   : " + t.networktype);
const dom = (t.domain||"").toUpperCase();
if (dom && dom !== "POWER") fl.push("  🌐 Domain    : " + t.domain);
if (t.sitepriority)   fl.push("  🎯 Priority  : " + t.sitepriority);
if (t.standardalarmseverity) fl.push("  🔔 Severity  : " + t.standardalarmseverity);
if (t.acknowledged)   fl.push("  ✅ Ack       : " + t.acknowledged);
if (t.sitecode)       fl.push("  🔍 Site Code : " + t.sitecode);
if (t.isrootne==="Yes") fl.push("  🌳 Root NE   : Yes");

// ── Helpers ───────────────────────────────────────────────
const W = 46;
const SEP  = "━".repeat(W);
const hr   = "─".repeat(W);

// Build group from records using tally for real count
// tally = actual occurrence count per alarm type from API
function buildNameGroups(records) {
  const g = {};
  for (const r of records) {
    const k = r.alarmname || r.rawalarmname || "Unknown";
    // Use tally (API actual count) if available and > 1
    const cnt = Number(r.tally || r.count || r.occurrences || 1);
    g[k] = (g[k] || 0) + cnt;
  }
  return Object.entries(g).sort((a,b) => b[1]-a[1]);
}

function barLine(label, count, maxV) {
  const lb = label.length > 28 ? label.slice(0,27)+"…" : label.padEnd(28," ");
  const cn = String(count).padStart(5," ");
  const barLen = maxV > 0 ? Math.round((count/maxV)*10) : 0;
  const bar = "█".repeat(barLen) + "░".repeat(10-barLen);
  return `  ${lb} ${cn}  ${bar}`;
}

// ── Build reply ───────────────────────────────────────────
let reply = `📡 NOC Report — ${t.start_local}\n`;
reply += `   Period  : ${t.start_local.slice(11)} → ${t.end_local.slice(11)}\n`;
reply += SEP + "\n";

if (fl.length) {
  reply += "🔎 Filters:\n" + fl.join("\n") + "\n";
  reply += hr + "\n";
}

reply += `📊 TOTAL  : ${finalTotal} alarm${finalTotal !== 1 ? "s" : ""}\n`;
reply += hr + "\n";

// ── BREAKDOWN ─────────────────────────────────────────────
if (unique.length > 0) {
  const nameGroups = buildNameGroups(unique);
  const groupTotal = nameGroups.reduce((s,[,v]) => s+v, 0);

  if (isSiteDown && !co) {
    // Site list mode
    const top = Math.min(15, unique.length);
    reply += `🏗️  Top ${top} Affected Sites:\n\n`;
    reply += "  #   Code           Tech   Vendor\n";
    reply += "  " + "─".repeat(38) + "\n";
    for (let i=0; i<top; i++) {
      const r = unique[i];
      const n = String(i+1).padStart(2);
      const sc = (r.sitecode||r.sitename||"?").padEnd(14);
      const tc = (r.networktype||"?").padEnd(6);
      const vn = (r.vendor||"?");
      reply += `  ${n}. ${sc} ${tc}  ${vn}\n`;
    }
    if (dedupedTotal > top) reply += `\n  ... and ${dedupedTotal-top} more sites\n`;

  } else {
    // Breakdown by alarm name (power + all other count queries)
    const label = isPower ? "⚡ By Alarm Type:" : "📋 By Alarm Name:";
    reply += label + "\n";
    const maxV = nameGroups[0]?.[1] || 1;
    for (const [k,v] of nameGroups) reply += barLine(k, v, maxV) + "\n";

    if (apiTotal > groupTotal) {
      reply += `\n  ℹ️  Based on ${unique.length} of ${apiTotal} records\n`;
    }
  }
}

reply += SEP;

return [{ json: { reply, total: finalTotal, api_total: apiTotal, deduped_total: dedupedTotal } }];

const aiOutput = $('Resolve Location').item.json || {}; 
const sqlQuery = $('Build SQL').item.json ? $('Build SQL').item.json.sql : "No SQL generated";
const sqlResults = $items("Get Alarm Names From Mapping").map(i => i.json);
const apiPayload = $('Build API Payload').item.json ? $('Build API Payload').item.json.payload : {};
const finalCount = $items("Deduplicate And Format Reply").length;

let originalApiCount = 0;
try {
  originalApiCount = $items("Normalize And Post Filter").length;
} catch(e) {}

const debugData = {
  "1_user_request": {
    "question": aiOutput.user_question || "unknown",
    "intent_interpreted": aiOutput.intent || "unknown"
  },
  "2_ai_extraction": {
    "category": aiOutput.category,
    "vendor": aiOutput.vendor,
    "technology": aiOutput.technology,
    "networktype": aiOutput.networktype,
    "filters": {
      "isvip": aiOutput.isvip,
      "sitedownflag": aiOutput.sitedownflag,
      "severity": aiOutput.severity
    }
  },
  "3_geography": {
    "raw_input": aiOutput.region_input,
    "resolved_pipe_string": aiOutput.location_resolved
  },
  "4_database_mapping": {
    "sql_executed": sqlQuery,
    "alarms_found_count": sqlResults.length,
    "alarm_names": sqlResults.map(r => r.alarm_name)
  },
  "5_api_execution": {
    "actual_payload_sent": apiPayload,
    "raw_records_returned": originalApiCount
  },
  "6_post_processing": {
    "deduplicated_final_count": finalCount
  }
};

const respItems = $items("Deduplicate And Format Reply");
let finalReplyMsg = "Done";
if (respItems.length > 0 && respItems[0].json && respItems[0].json.reply) {
    finalReplyMsg = respItems[0].json.reply;
}

return {
    reply: finalReplyMsg,
    total: finalCount,
    debug: debugData
};
